async function callGroq(prompt) {
  const r=await fetch(GROQ_URL,{method:"POST",
    headers:{"Content-Type":"application/json","Authorization":`Bearer ${GROQ_KEY}`},
    body:JSON.stringify({model:"llama-3.3-70b-versatile",max_tokens:700,messages:[
      {role:"system",content:"Tu es un assistant biomÃ©canique clinique expert. RÃ©ponds en franÃ§ais, structurÃ©."},
      {role:"user",content:prompt}]})});
  if(!r.ok) throw new Error("Groq error");
  const d=await r.json();
  return d.choices?.[0]?.message?.content||"Indisponible.";
}

