const MiniRing = ({val,color,size=42}) => {
  const r=16,cx=21,cy=21,circ=2*Math.PI*r,dash=(val/100)*circ;
  return(
    <svg width={size} height={size} viewBox="0 0 42 42">
      <circle cx={cx} cy={cy} r={r} fill="none" stroke="#E4E9F2" strokeWidth={5}/>
      <circle cx={cx} cy={cy} r={r} fill="none" stroke={color} strokeWidth={5}
        strokeDasharray={`${dash} ${circ}`} strokeLinecap="round" transform={`rotate(-90 ${cx} ${cy})`}/>
      <text x={cx} y={cy+4} textAnchor="middle" fill={C.pri} fontSize={10} fontWeight={700}>{val}</text>
    </svg>
  );
};

